export const createElement=(tag,props,...childrens)=>{let element,childNode;let fragment=document.createDocumentFragment();if("function"==typeof tag)element=tag(props,...childrens);else if(element=document.createElement(tag),null!=props)for(let attribute in props)"style"===attribute?Object.assign(element.style,props.style):element.setAttribute(attribute,props[attribute]);return childrens.forEach(node=>{"object"==typeof node?fragment.appendChild(node):(childNode=document.createTextNode(node),fragment.appendChild(childNode))}),element.appendChild(fragment),element};